#include <bits/stdc++.h>
using namespace std;
int main(){string s;cin>>s;stack<long long>st;for(char c:s){if(isdigit((unsigned char)c))st.push(c-'0');else{long long b=st.top();st.pop();long long a=st.top();st.pop();st.push(c=='+'?a+b:c=='-'?a-b:a*b);}}printf("%lld\n",st.top());}
